class City {
  final String id;
  final String name;

  City({
    required this.id,
    required this.name,
  });

  // Convert to JSON
  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
    };
  }

  // Create from JSON
  factory City.fromJson(Map<String, dynamic> json) {
    return City(
      id: json['id'],
      name: json['name'],
    );
  }
}

class Masjid {
  String id;
  String name;
  String societyId;
  String imamId;
  String fajr;
  String zuhr;
  String asr;
  String maghrib;
  String isha;
  String jummah;
  String status;

  Masjid({
    required this.id,
    required this.name,
    required this.societyId,
    required this.imamId,
    required this.fajr,
    required this.zuhr,
    required this.asr,
    required this.maghrib,
    required this.isha,
    required this.jummah,
    this.status = 'pending',
  });

  factory Masjid.fromJson(Map<String, dynamic> json) {
    return Masjid(
      id: json['id'] ?? '',
      name: json['name'] ?? '',
      societyId: json['society_id'] ?? '',
      imamId: json['imam_id'] ?? '',
      fajr: json['fajr'] ?? '',
      zuhr: json['zuhr'] ?? '',
      asr: json['asr'] ?? '',
      maghrib: json['maghrib'] ?? '',
      isha: json['isha'] ?? '',
      jummah: json['jummah'] ?? '',
      status: json['status'] ?? 'pending',
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
      'society_id': societyId,
      'imam_id': imamId,
      'fajr': fajr,
      'zuhr': zuhr,
      'asr': asr,
      'maghrib': maghrib,
      'isha': isha,
      'jummah': jummah,
      'status': status,
    };
  }
}

class Restaurant {
  String id;
  String name;
  String societyId;
  String ownerId;
  String phone;
  String category;
  bool deliveryAvailable;
  String status;

  Restaurant({
    required this.id,
    required this.name,
    required this.societyId,
    required this.ownerId,
    required this.phone,
    required this.category,
    this.deliveryAvailable = false,
    this.status = 'pending',
  });

  factory Restaurant.fromJson(Map<String, dynamic> json) {
    return Restaurant(
      id: json['id'] ?? '',
      name: json['name'] ?? '',
      societyId: json['society_id'] ?? '',
      ownerId: json['owner_id'] ?? '',
      phone: json['phone'] ?? '',
      category: json['category'] ?? '',
      deliveryAvailable: json['delivery_available'] ?? false,
      status: json['status'] ?? 'pending',
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
      'society_id': societyId,
      'owner_id': ownerId,
      'phone': phone,
      'category': category,
      'delivery_available': deliveryAvailable,
      'status': status,
    };
  }
}

class Service {
  String id;
  String name;
  String serviceType;
  String societyId;
  String providerId;
  String phone;
  int experience;
  String status;

  Service({
    required this.id,
    required this.name,
    required this.serviceType,
    required this.societyId,
    required this.providerId,
    required this.phone,
    required this.experience,
    this.status = 'pending',
  });

  factory Service.fromJson(Map<String, dynamic> json) {
    return Service(
      id: json['id'] ?? '',
      name: json['name'] ?? '',
      serviceType: json['service_type'] ?? '',
      societyId: json['society_id'] ?? '',
      providerId: json['provider_id'] ?? '',
      phone: json['phone'] ?? '',
      experience: json['experience'] ?? 0,
      status: json['status'] ?? 'pending',
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
      'service_type': serviceType,
      'society_id': societyId,
      'provider_id': providerId,
      'phone': phone,
      'experience': experience,
      'status': status,
    };
  }
}

// App Constants
class AppConstants {
  // User Roles
  static const String ROLE_ADMIN = "admin";
  static const String ROLE_RESIDENT = "resident";
  static const String ROLE_IMAM = "imam";
  static const String ROLE_RESTAURANT_OWNER = "restaurant_owner";
  static const String ROLE_SERVICE_PROVIDER = "service_provider";

  // Status
  static const String STATUS_PENDING = "pending";
  static const String STATUS_APPROVED = "approved";
  static const String STATUS_REJECTED = "rejected";

  // Collections
  static const String COLLECTION_USERS = "users";
  static const String COLLECTION_CITIES = "cities";
  static const String COLLECTION_SOCIETIES = "societies";
  static const String COLLECTION_MASJIDS = "masjids";
  static const String COLLECTION_RESTAURANTS = "restaurants";
  static const String COLLECTION_SERVICES = "services";
  static const String COLLECTION_EMERGENCY = "emergency_contacts";
}

import 'package:flutter/material.dart';

class MenuCard extends StatelessWidget {
  final String title;
  final IconData icon;
  final VoidCallback onTap;

  const MenuCard({
    required this.title,
    required this.icon,
    required this.onTap,
  });

  @override
  Widget build(BuildContext context) {
    return GestureDetector(
      onTap: onTap,
      child: Card(
        elevation: 3,
        shape: RoundedRectangleBorder(
          borderRadius: BorderRadius.circular(10),
        ),
        child: Container(
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(10),
            gradient: LinearGradient(
              colors: [Colors.green[300]!, Colors.green[700]!],
              begin: Alignment.topLeft,
              end: Alignment.bottomRight,
            ),
          ),
          child: Center(
            child: Column(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                Icon(icon, size: 40, color: Colors.white),
                SizedBox(height: 10),
                Text(
                  title,
                  textAlign: TextAlign.center,
                  style: TextStyle(
                    fontSize: 14,
                    fontWeight: FontWeight.bold,
                    color: Colors.white,
                  ),
                )
              ],
            ),
          ),
        ),
      ),
    );
  }
}
